import { useEffect, useMemo, useState } from "react";
import api from "../api";

const PAGE_SIZE = 9;
const money = v => (Number(v||0)).toLocaleString("vi-VN")+" ₫";

export default function Contracts(){
    const [rows,setRows]=useState([]);
    const [page,setPage]=useState(0);
    const [totalPages,setTotalPages]=useState(1);
    const [loading,setLoading]=useState(true);

    const [customers,setCustomers]=useState([]); // for select
    const [showModal,setShowModal]=useState(false);
    const [editing,setEditing]=useState(null);
    const [form,setForm]=useState({
        code:"", customerId:"", value:0, signed:"", duration:30, type:"Thi công", status:"Đang thực hiện"
    });

    function normalizeList(d){ return Array.isArray(d)?{list:d,pages:1}:{list:d?.content||[],pages:d?.totalPages||1}; }

    useEffect(()=>{ (async()=>{
        try{
            const {data}=await api.get("/api/customers",{params:{page:0,size:1000}});
            setCustomers(Array.isArray(data)?data:(data?.content||[]));
        }catch{}
    })(); },[]);

    useEffect(()=>{ load(); },[page]);

    async function load(){
        setLoading(true);
        try{
            const {data}=await api.get("/api/contracts",{params:{page,size:PAGE_SIZE,sort:"id,desc"}});
            const {list,pages}=normalizeList(data);
            setRows(list); setTotalPages(pages);
        }catch(e){ console.error(e); setRows([]); setTotalPages(1); }
        finally{ setLoading(false); }
    }

    function openCreate(){
        setEditing(null);
        setForm({code:"", customerId: customers[0]?.id || "", value:0, signed:new Date().toISOString().slice(0,10), duration:30, type:"Thi công", status:"Đang thực hiện"});
        setShowModal(true);
    }
    function openEdit(row){
        setEditing(row);
        setForm({
            code: row.code || row.contractCode || "",
            customerId: row.customerId || row.customer?.id || "",
            value: row.totalAmount ?? row.value ?? 0,
            signed: row.signedDate || row.signed || "",
            duration: row.duration ?? row.termDays ?? 30,
            type: row.contractType || row.type || "Thi công",
            status: row.status || "Đang thực hiện"
        });
        setShowModal(true);
    }

    async function save(e){
        e.preventDefault();
        const payload = {
            code: form.code,
            customerId: form.customerId ? Number(form.customerId) : null,
            totalAmount: Number(form.value),
            signedDate: form.signed,
            duration: Number(form.duration),
            contractType: form.type,
            status: form.status
        };
        try{
            if(editing) await api.put(`/api/contracts/${editing.id}`, payload);
            else        await api.post("/api/contracts", payload);
            setShowModal(false); await load();
        }catch(err){ alert(err?.response?.data?.message || "Lưu hợp đồng thất bại"); }
    }

    async function remove(row){
        if(!window.confirm(`Xoá hợp đồng ${row.code || row.contractCode}?`)) return;
        try{ await api.delete(`/api/contracts/${row.id}`); await load(); }
        catch(err){ alert(err?.response?.data?.message || "Xoá hợp đồng thất bại"); }
    }

    const normalized = useMemo(()=>rows.map(c=>({
        id:c.id,
        code:c.code || c.contractCode || `HD-${c.id}`,
        customerId:c.customerId || c.customer?.id,
        customerName: c.customerName || c.customer?.name || "",
        value: c.totalAmount ?? c.value ?? 0,
        signed: c.signedDate || c.signed || "",
        duration: c.duration ?? c.termDays ?? 0,
        type: c.contractType || c.type || "",
        status: c.status || "Đang thực hiện"
    })),[rows]);

    return (
        <div className="space-y-4">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-lg font-semibold">Hợp đồng</h2>
                    <p className="text-sm text-slate-500">Theo dõi mã, loại, giá trị và trạng thái</p>
                </div>
                <button onClick={openCreate} className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">Thêm hợp đồng</button>
            </div>

            {loading? <div className="p-6 bg-white rounded-2xl border">Đang tải…</div> : (
                <>
                    <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
                        {normalized.map(c=>(
                            <div key={c.id} className="p-4 rounded-2xl bg-white border border-indigo-100 shadow flex flex-col gap-3">
                                <div className="flex items-start justify-between">
                                    <div>
                                        <div className="font-semibold">{c.code}</div>
                                        <div className="text-sm text-slate-600">{c.customerName || customers.find(x=>x.id===c.customerId)?.name || "-"}</div>
                                        <div className="text-xs text-slate-500 mt-1">{c.type} • Ký: {c.signed} • Hạn: {c.duration} ngày</div>
                                    </div>
                                    <span className={"px-2 py-0.5 rounded-full text-xs "+
                                        (c.status==="Đã hoàn tất"?"bg-emerald-100 text-emerald-700": c.status==="Huỷ"?"bg-rose-100 text-rose-700":"bg-amber-100 text-amber-700")}>
                    {c.status}
                  </span>
                                </div>
                                <div className="grid grid-cols-3 gap-3">
                                    <div className="p-3 rounded-xl bg-indigo-50/50">
                                        <div className="text-xs text-slate-500">Giá trị</div>
                                        <div className="font-semibold">{money(c.value)}</div>
                                    </div>
                                    <div className="p-3 rounded-xl bg-slate-50">
                                        <div className="text-xs text-slate-500">Đã thu</div>
                                        <div className="font-semibold">—</div>
                                    </div>
                                    <div className="p-3 rounded-xl bg-slate-50">
                                        <div className="text-xs text-slate-500">Còn lại</div>
                                        <div className="font-semibold">—</div>
                                    </div>
                                </div>
                                <div className="flex items-center justify-end gap-2">
                                    <button onClick={()=>openEdit(c)} className="px-2 py-1 rounded bg-indigo-50 text-indigo-700 hover:bg-indigo-100">Sửa</button>
                                    <button onClick={()=>remove(c)} className="px-2 py-1 rounded bg-rose-50 text-rose-700 hover:bg-rose-100">Xóa</button>
                                </div>
                            </div>
                        ))}
                    </div>

                    <div className="flex gap-2 mt-4">
                        <button className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                                onClick={()=>setPage(p=>Math.max(0,p-1))} disabled={page<=0}>← Trước</button>
                        <div className="px-3 py-1.5 text-sm">Trang {page+1}/{totalPages}</div>
                        <button className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                                onClick={()=>setPage(p=>p+1)} disabled={page+1>=totalPages}>Sau →</button>
                    </div>
                </>
            )}

            {/* Modal */}
            {showModal && (
                <div className="fixed inset-0 z-40 bg-black/40 grid place-items-center p-4">
                    <div className="w-full max-w-3xl bg-white rounded-2xl shadow-xl border border-indigo-100">
                        <div className="p-5 border-b flex items-center justify-between">
                            <div className="font-semibold">{editing?"Sửa hợp đồng":"Thêm hợp đồng"}</div>
                            <button className="text-slate-500 hover:text-slate-700" onClick={()=>setShowModal(false)}>Đóng</button>
                        </div>
                        <form onSubmit={save} className="p-5 grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className="text-sm text-slate-600">Mã hợp đồng</label>
                                <input required value={form.code} onChange={e=>setForm(f=>({...f,code:e.target.value}))}
                                       className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"/>
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Khách hàng</label>
                                <select required value={form.customerId} onChange={e=>setForm(f=>({...f,customerId:e.target.value}))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow">
                                    {customers.map(c=><option key={c.id} value={c.id}>{c.name}</option>)}
                                </select>
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Giá trị (₫)</label>
                                <input required type="number" min="0" value={form.value} onChange={e=>setForm(f=>({...f,value:e.target.value}))}
                                       className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"/>
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Ngày ký</label>
                                <input required type="date" value={form.signed} onChange={e=>setForm(f=>({...f,signed:e.target.value}))}
                                       className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"/>
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Thời hạn (ngày)</label>
                                <input required type="number" min="1" value={form.duration} onChange={e=>setForm(f=>({...f,duration:e.target.value}))}
                                       className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"/>
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Loại hợp đồng</label>
                                <select value={form.type} onChange={e=>setForm(f=>({...f,type:e.target.value}))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow">
                                    <option>Thiết kế</option>
                                    <option>Thi công</option>
                                    <option>Tổng thầu</option>
                                </select>
                            </div>
                            <div className="md:col-span-2">
                                <label className="text-sm text-slate-600">Trạng thái</label>
                                <select value={form.status} onChange={e=>setForm(f=>({...f,status:e.target.value}))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow">
                                    <option>Đang thực hiện</option>
                                    <option>Đã hoàn tất</option>
                                    <option>Huỷ</option>
                                </select>
                            </div>
                            <div className="md:col-span-2 flex items-center justify-end gap-2 pt-2">
                                <button type="button" className="px-3 py-2 rounded-lg bg-slate-100 hover:bg-slate-200" onClick={()=>setShowModal(false)}>Huỷ</button>
                                <button className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">Lưu</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}
